mapper.update:
UPDATE setting_code
SET
    setting_name = #{settingName},
    default_yn = #{defaultYn},
    use_yn = #{useYn}
WHERE setting_code_id = #{settingCodeId}

mapper.select:
SELECT COUNT(*)
FROM setting_code
WHERE user_id = #{userId}
  AND setting_group_name = #{settingGroupName}
  AND default_yn = 'Y'

SELECT COUNT(*)
FROM setting_code
WHERE user_id = #{userId}
  AND setting_group_name = #{settingGroupName}
  AND setting_name = #{settingName}
